var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"휴우… 요즘 들어 근무가 더 빡세네.","JPN":"ふう……最近、仕事がきついんだよな。","ENG":"Phew... Duty's been rough lately.","TWN":"呼……最近工作越來越緊張了。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"이러다 과로로 죽는 거 아닌가 몰라.","JPN":"これでは過労で死ぬんじゃないか？","ENG":"Feels like I'm gonna drop dead from overwork.","TWN":"這樣下去會不會累死啊。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"상황이 상황이니 어쩔 수 없지. 관리국에서 구원기사단의 고유무장을 아예 우리 쪽에 넘겼다잖아.","JPN":"こんな状況だし、仕方ない。管理局が救世騎士団の固有武装を全部こっちに渡したらしいじゃないか。","ENG":"Given the situation, we don't have much choice. The Administration handed over the Knights of Redemption's Unique Gear to us entirely.","TWN":"情況特殊，也沒辦法。管理局已經把救贖騎士團的專屬武裝完全交給我們了。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"무구의 유사성이 있으니 기사단이 발 빼지 못하도록 끌어들인 셈이지만…….","JPN":"武具の類似性があるから、騎士団が逃げられないように引き込んだようなものだけど……","ENG":"It's partly because of the Armament's similarity, so now the Order is tied in for good...","TWN":"因為有武具的相似性，所以算是把騎士團拖入了無法脫身的境地……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"기사단의 건틀렛 참가 이후 사람들의 시선도 우호적으로 변했고, 좋은 게 좋은 거지.","JPN":"騎士団もガントレットに参加した後から周りの視線も友好的になったし、いいことなんだろう。","ENG":"But since they joined the Gauntlet, public opinion's warmed up. Win-win, I say.","TWN":"騎士團加入聖鎧之後，人們的目光也變得友善了，見好就收吧。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"그래. 이 넓은 본부를 몇 바퀴째 돌고 있는 것만 빼면 완벽하네.","JPN":"そう。この広い本部を何周も回ってることを除けば、完璧だ。","ENG":"Yeah, it's all good. Except for the part where we're stuck making endless laps around this massive base.","TWN":"是啊。除了在這個寬廣的總部繞了好幾圈之外，一切都很完美。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"단장님도 복귀하셨겠다. 당분간 별일 없었으면 좋겠구만.","JPN":"団長も復帰したし、しばらくは静かであってほしいな。","ENG":"At least Captain's back now. Hopefully things will calm down for a while.","TWN":"團長也回來了，希望最近沒什麼特別的事情發生。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"그거 플래그야, 인마.","JPN":"おい、それフラグだぞ。","ENG":"You just jinxed it, man.","TWN":"那是個旗幟，小子。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"시간도 됐으니 슬슬 집무실이나 둘러보고 끝내자고.","JPN":"もう時間だし、そろそろ執務室を回って終わらせようぜ。","ENG":"Anyway, our shift's almost done. Let's swing by the office and wrap up.","TWN":"時間也差不多了，快去巡視一下辦公室，然後結束吧。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"집무실? 거긴 프레이더 경이 용무 때문에 쓴다고 하지 않으셨나?","JPN":"執務室？　そこはフレイダー卿が用務で使ってるんじゃないのか？","ENG":"The office? Wasn't Sir Frayder using it today?","TWN":"辦公室？那裡不是說弗雷德有事要用嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"단장님 명령이야. 무슨 일이 벌어질지 모르니 슬쩍 보고 오라더라.","JPN":"団長命令なんだ。何があるかわからないから、こっそり見てくるようにって。","ENG":"Captain's orders. Just wants us to take a peek, in case something comes up.","TWN":"團長的命令。讓我去看看發生了什麼事，以防萬一。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"그냥 별일 없나 살피기만 하는 거니까 너무 걱정 마.","JPN":"念のためチェックするだけだから、あんまり心配するなよ。","ENG":"We're not doing anything serious. Just a quick look. Don't worry.","TWN":"只是看看有沒有什麼事，別太擔心了。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"늦어서 미안하군.","JPN":"遅くなってすまない。","ENG":"Apologies for the delay.","TWN":"……我來晚了，抱歉。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"다른 기사들의 눈을 피하는데 제법 시간이 걸렸다.","JPN":"他の騎士の目を避けるのに時間がかかってしまった。","ENG":"It took some time to avoid the other knights' attention.","TWN":"花了相當長的時間才避開其他騎士的視線。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"네놈…! 뚫린 입이라고 말은 잘하는구나!","JPN":"貴様……！　ふざけやがる！","ENG":"You insolent brat...! You sure talk like you've done nothing wrong!","TWN":"你……！嘴巴倒是挺能說的嘛！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"분명 말했을 텐데. 이번 기회에 확실하게 블루시프트를 끝장내라고!","JPN":"確かに言ったはずだ。この機会に確実にブルーシフトを始末しろと！","ENG":"I told you clearly. This was your chance to crush Blue Shift once and for all!","TWN":"我肯定說過了。這次機會一定要徹底解決藍移問題！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그런데 전임 기사단장도 아닌 현 기사단장에게 패배하다니… 카란티시르 녀석은 대체 뭘 한 거냐!","JPN":"なのに前騎士団長でもなく、現騎士団長に負けるとは……カランティシルのやつはいったい何をしていたんだ！","ENG":"But you lost, not even to the former captain, but to the current one?! What was Carantisir even doing?!","TWN":"居然輸給了現任騎士團長而不是前任騎士團長……卡蘭堤西爾那傢伙到底幹了什麼！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"어떤 전장에서든 변수는 있는 법이다.","JPN":"どんな戦場であろうと、不確定要素はあるものだ。","ENG":"Every battlefield has its variables.","TWN":"任何戰場上都存在變數。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"무엇보다, 그녀의 안배가 무엇이었는지를 생각하면 결코 우스운 상대는 아니었어.","JPN":"なにより、彼女が用意したものが何なのかを考えると、決して侮れない相手だった。","ENG":"And considering her arrangements, she was never a lightweight.","TWN":"最重要的是，想到她的安排是什麼，絕對不是一個可笑的對手。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"막 기사단에 들어온 애송이 주제에 말이 짧구나!!","JPN":"騎士団に入ったばかりの小娘のくせに、けしからん！！","ENG":"Bold words for a kid who just joined the Order!","TWN":"剛加入騎士團的小丫頭，口氣倒是不小啊！！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그래. 장기말은 장기말로써 봐야지. 그 이상의 것을 기대하면 쓰나.","JPN":"そう。駒は駒として扱うもの。それ以上を期待してはならない。","ENG":"Well, pawns are pawns. Can't expect much more than that.","TWN":"好，棋子就該作為棋子來看待。不能有更多的期待。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"결국 기사단의 실권이 내게 쥐여 쥘 건 변함없으니… 그저 사소한 기다림일 뿐이야.","JPN":"私が騎士団の実権を握ることには変わりがない……そう長く待たなくてもいいだろう。","ENG":"In the end, I still hold the real power over the Order... This is nothing more than a brief delay.","TWN":"最終騎士團的實權還是會落到我手上……只是需要稍作等待而已。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"부탁한 물건은?","JPN":"頼んだものは？","ENG":"And the item I asked for?","TWN":"要的東西呢？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"흥. 일 하나 제대로 못 처리하면서 뻔뻔한 놈들 같으니.","JPN":"ふん。仕事もできないくせに、図々しいやつらだ。","ENG":"Hmph. Acting all smug when you couldn't even do your job right.","TWN":"哼。連一件事情都處理不好，真是厚顏無恥的傢伙。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"기사단이 맡고 있는 구원기사단의 고유무장이다.","JPN":"騎士団が預かっている救世騎士団の固有武装だ。","ENG":"It's the Unique Gear from the Knights of Redemption currently in our care.","TWN":"這是騎士團負責的救贖騎士團的專屬武裝。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};